import numpy as np

def compute_awq_scale(weights, activation_magnitudes, alpha=0.5):
    return weights * (activation_magnitudes ** alpha)

def run_practice():
    w = np.array([1.0, 1.0])
    m = np.array([4.0, 1.0])
    scale = compute_awq_scale(w, m, 0.5)
    assert np.allclose(scale, np.array([2.0, 1.0]))
    print('[PASS] AWQ scaling calculations verified.')

if __name__ == '__main__':
    run_practice()
